class Solution:
    def minimizeXor(self, num1: int, num2: int) -> int:
        c = bin(num2).count('1')
        x = 0
        remaining = c
        for i in range(30, -1, -1):
            mask = 1 << i
            if (num1 & mask) and remaining > 0:
                x |= mask
                remaining -= 1
        if remaining > 0:
            for i in range(0, 31):
                mask = 1 << i
                if not (num1 & mask):
                    x |= mask
                    remaining -= 1
                    if remaining == 0:
                        break
        return x

